-- Populating Ward Centroids from storage baseline
-- Matching Logic: Lowercase, trimmed, ward suffix removed
BEGIN;
CREATE TEMP TABLE ward_import (v_name text, v_county text, v_lat float8, v_lng float8) ON COMMIT DROP;

-- Update the wards table using the matched data
-- We use a double check: direct lower match OR name without 'ward' suffix match
UPDATE public.wards w
SET 
  latitude = i.v_lat,
  longitude = i.v_lng
FROM ward_import i
WHERE 
  LOWER(w.county) = i.v_county
  AND (
    LOWER(w.ward_name) = i.v_name 
    OR TRIM(TRAILING ' ward' FROM LOWER(w.ward_name)) = i.v_name
    OR i.v_name = TRIM(TRAILING ' ward' FROM LOWER(w.ward_name))
  );

COMMIT;
